const t=[{id:"bridge-1",type:"bridge",name:"双石桥",area:"大研",location:{lat:26.879763,lng:100.231997},address:"大水车旁",description:'双石桥(玉龙桥)位于古城北面玉河水入城处，河水在此分流为东、中、西三条河。光绪《丽江府志》记载："旧志，在城西北二里，两孔行水，玉河于此分派。"西连新华街，东往新义街，明代土知府建。为双孔石拱平桥，桥身长10余米，桥宽约4米，两边设坐凳式石板护栏。1959年拆双石桥，在桥北新建混凝土结构玉龙桥，桥长12米，宽14米。1987年扩建加宽两边人行道各5米，桥面增宽至24米。它作为丽江新老城的连接点，继续着自古以来把玉河水一分为三的使命，加上两架大水车往河里一"坐"，水流轮转，昼夜不停，给古城平添了一份优雅，一种动感之美。',basicInfo:"双孔石拱桥，玉河水入城分流处",photos:["https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=800&q=70","https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?auto=format&fit=crop&w=800&q=70","https://images.unsplash.com/photo-1567696911989-2e77983f7088?auto=format&fit=crop&w=800&q=70"],heritageSubType:"/",extra:{material:"石材",loadCapacity:"/",bridgeHeight:"3.7",pointWidth:"22.4"}},{id:"bridge-2",type:"bridge",name:"大石桥",area:"大研",location:{lat:26.876522,lng:100.235022},address:"新义街与五一街交汇处",description:"大石桥位于古城中心，是新义街与五一街兴仁巷交汇处的标志性建筑。该桥为单孔石拱桥，桥身以本地青石砌成，桥面铺石板，两侧设有石栏杆。桥下河水清澈，两岸垂柳成行，是古城最具画面感的景点之一。",basicInfo:"单孔石拱，古城繁华地段",photos:["https://images.unsplash.com/photo-1528161344942-b5523058c97b?auto=format&fit=crop&w=800&q=70","https://images.unsplash.com/photo-1548802673-380ab8ebc7b7?auto=format&fit=crop&w=800&q=70","https://images.unsplash.com/photo-1536634518009-96cde641b145?auto=format&fit=crop&w=800&q=70"],drawings:["1、遗产保护/4、古桥大石桥大石桥结构图.png"],heritageSubType:"/",extra:{material:"石材（青石）",loadCapacity:"/",bridgeHeight:"3.2",pointWidth:"4.5"}},{id:"bridge-3",type:"bridge",name:"万子桥",area:"大研",location:{lat:26.873522,lng:100.232522},address:"四方街南侧",description:'万子桥位于四方街南侧，是通往古城南部的重要通道。该桥为单孔石拱桥，造型古朴典雅。桥名寓意"万子千孙"，是古城居民祈福的象征。桥两岸保留了大量传统民居，是体验古城生活气息的绝佳场所。',basicInfo:"单孔石拱，寓意吉祥",photos:["https://images.unsplash.com/photo-1536634518009-96cde641b145?auto=format&fit=crop&w=800&q=70","https://images.unsplash.com/photo-1567696911989-2e77983f7088?auto=format&fit=crop&w=800&q=70","https://images.unsplash.com/photo-1547981609-4b6bfe67ca0b?auto=format&fit=crop&w=800&q=70"],heritageSubType:"/",extra:{material:"石材",loadCapacity:"/",bridgeHeight:"2.8",pointWidth:"3.8"}},{id:"bridge-4",type:"bridge",name:"南门桥",area:"大研",location:{lat:26.871522,lng:100.236522},address:"古城南门口",description:"南门桥是古城南门外的标志性建筑，是游客进入古城的主要通道。该桥为单孔石平桥，宽阔平坦，桥栏以本地青石雕成。桥下河水潺潺，两岸商铺林立，是感受古城商业氛围的绝佳地点。",basicInfo:"石平桥，古城南门入口",photos:["https://images.unsplash.com/photo-1547981609-4b6bfe67ca0b?auto=format&fit=crop&w=800&q=70","https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=800&q=70","https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&w=800&q=70"],heritageSubType:"/",extra:{material:"石材（青石）",loadCapacity:"/",bridgeHeight:"2.5",pointWidth:"5.2"}},{id:"bridge-5",type:"bridge",name:"玉龙桥",area:"大研",location:{lat:26.880022,lng:100.231522},address:"玉河东路北端",description:"玉龙桥1959年建于原双石桥北侧，是为了适应城市交通发展而新建的混凝土结构桥梁。桥长12米，宽14米，1987年扩建加宽两边人行道各5米，桥面增宽至24米。该桥是进出古城的重要通道，也是古城现代发展的见证。",basicInfo:"混凝土结构，1959年建",photos:["https://images.unsplash.com/photo-1567696911989-2e77983f7088?auto=format&fit=crop&w=800&q=70","https://images.unsplash.com/photo-1528161344942-b5523058c97b?auto=format&fit=crop&w=800&q=70"],heritageSubType:"/",extra:{material:"混凝土",loadCapacity:"城市-B级",bridgeHeight:"4.2",pointWidth:"24"}}];export{t as b};
